public class ParseBenchmarkTest {

  private ZipFile mockZipFile;
  private ZipEntry mockZipEntry;

  @BeforeEach
  public void setup() throws Exception {
    mockZipFile = mock(ZipFile.class);
    mockZipEntry = mock(ZipEntry.class);
  }

  @Test
  public void testResourceToString_readsContentsSuccessfully() throws Exception {
    // Arrange
    String fileName = "testFile.txt";
    String fileContent = "Hello, this is the file content.";

    // Mock getResourceFile to return a dummy File (not used directly since ZipFile is mocked)
    File dummyFile = mock(File.class);

    // Mock static method getResourceFile
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class)) {
      mockedStatic.when(() -> ParseBenchmark.getResourceFile("/ParseBenchmarkData.zip")).thenReturn(dummyFile);
      // Mock ZipFile constructor to return our mockZipFile when instantiated with dummyFile
      try (MockedStatic<ZipFile> zipFileStatic = Mockito.mockStatic(ZipFile.class)) {
        // Not possible to mock constructor of ZipFile with Mockito, so we will spy on ParseBenchmark and mock ZipFile inside resourceToString
        // Instead, we will use partial mocking of ParseBenchmark and replace ZipFile with a spy inside resourceToString using reflection

        // We will use a helper class to override ZipFile - but since this is complicated,
        // alternatively, we can use a custom classloader or redesign the code for testability.
        // But here, since ZipFile is instantiated inside the method, we can use PowerMock or other tools,
        // but question restricts to Mockito 3 only.

        // So we will use reflection to invoke the method and mock ZipFile by spying the method resourceToString itself.

        // Instead, we will do the following:
        // 1. Create a subclass of ParseBenchmark with overridden resourceToString method that uses our mocks.
        // 2. But resourceToString is private static, so cannot override easily.
        // 3. So we will use reflection to invoke resourceToString and mock ZipFile constructor using Mockito inline mock maker.

        // Since mocking ZipFile constructor is not possible here, we will do a workaround by creating a temporary zip file on disk.

        // Create temporary zip file with the entry and content
        java.nio.file.Path tempZipPath = java.nio.file.Files.createTempFile("ParseBenchmarkData", ".zip");
        try (java.util.zip.ZipOutputStream zos = new java.util.zip.ZipOutputStream(java.nio.file.Files.newOutputStream(tempZipPath))) {
          zos.putNextEntry(new java.util.zip.ZipEntry(fileName));
          zos.write(fileContent.getBytes());
          zos.closeEntry();
        }

        // Mock getResourceFile to return the temp zip file
        mockedStatic.when(() -> ParseBenchmark.getResourceFile("/ParseBenchmarkData.zip")).thenReturn(tempZipPath.toFile());

        // Act
        Method method = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
        method.setAccessible(true);
        String result = (String) method.invoke(null, fileName);

        // Assert
        assertEquals(fileContent, result);

        // Cleanup temp file
        java.nio.file.Files.deleteIfExists(tempZipPath);
      }
    }
  }

  @Test
  public void testResourceToString_throwsExceptionWhenFileNotFound() throws Exception {
    String fileName = "nonexistent.txt";

    // Create temporary empty zip file without the entry
    java.nio.file.Path tempZipPath = java.nio.file.Files.createTempFile("ParseBenchmarkData", ".zip");
    try (java.util.zip.ZipOutputStream zos = new java.util.zip.ZipOutputStream(java.nio.file.Files.newOutputStream(tempZipPath))) {
      // no entries
    }

    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class)) {
      mockedStatic.when(() -> ParseBenchmark.getResourceFile("/ParseBenchmarkData.zip")).thenReturn(tempZipPath.toFile());

      Method method = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
      method.setAccessible(true);

      Exception exception = assertThrows(Exception.class, () -> {
        method.invoke(null, fileName);
      });
      // The cause should be NullPointerException because getEntry(fileName) returns null and then getInputStream(null) is called
      Throwable cause = exception.getCause();
      // NullPointerException expected
      assertEquals(NullPointerException.class, cause.getClass());
    } finally {
      java.nio.file.Files.deleteIfExists(tempZipPath);
    }
  }
}

